mapper.select:
SELECT item_id , portfolio_id , stock_cd , hold_qty , buy_price , buy_dt , buy_amount , currency , memo , use_yn , reg_dt , upd_dt FROM tbl_portfolio_item WHERE use_yn = 'Y'
AND portfolio_id = #{portfolioId}
AND stock_cd = #{stockCd}
ORDER BY buy_dt DESC

mapper.insert:
INSERT INTO tbl_portfolio_item (
     portfolio_id
   , stock_cd
   , hold_qty
   , buy_price
   , buy_dt
   , buy_amount
   , currency
   , memo
   , use_yn
   , reg_dt
   , upd_dt
) VALUES (
     #{portfolioId}
   , #{stockCd}
   , #{holdQty}
   , #{buyPrice}
   , #{buyDt}
   , #{holdQty} * #{buyPrice}
   , COALESCE(#{currency}, 'USD')
   , #{memo}
   , 'Y'
   , NOW()
   , NOW()
)

mapper.update:
UPDATE tbl_portfolio_item
   SET upd_dt = NOW()

     , hold_qty = #{holdQty}


     , buy_price = #{buyPrice}


     , buy_amount = COALESCE(#{holdQty}, hold_qty) * COALESCE(#{buyPrice}, buy_price)


     , buy_dt = #{buyDt}


     , currency = #{currency}


     , memo = #{memo}

 WHERE item_id = #{itemId}
   AND use_yn = 'Y'
